const request = $input.first().json;
const body = request.body ?? request;

const event = body.event ?? 'unknown';
const receivedAt = body.timestamp ? new Date(body.timestamp) : new Date();
const isTest = event === 'manual_test';

const date = receivedAt.toLocaleDateString('en-US', {
  weekday: 'long',
  month: 'long',
  day: 'numeric',
  timeZone: 'UTC',
});

const lines = [
  isTest
    ? 'Your RestFlow connection test completed successfully.'
    : 'Your overnight RestFlow workflow completed successfully.',
  '',
  `Brief prepared for ${date}.`,
  '',
  'Morning checklist:',
  '• Review today’s calendar',
  '• Choose your three most important tasks',
  '• Check urgent messages before opening everything else',
  '• Start with one focused 25-minute work session',
];

return [{
  json: {
    title: isTest ? 'RestFlow connection works' : 'Good morning',
    body: lines.join('\n'),
  },
}];
